[][538] +                const uint8_t *next;
[][539] +
[][540] +                /* If a short entry is found (less than 4 bytes), not only it
[][541] +                 * is invalid, but we cannot reliably locate the next entry.
[][542] +                 * Better stop at this point, and let the user know his/her
[][543] +                 * table is broken. */
[][544] +                if (h.length < 4)
[][545] +                        break;
[][546] +
