[][530] +        for (uint16_t i = 0; (i < num || num == 0) && data + 4 <= buf + len; i++) {
[][531] +                struct dmi_header h = (struct dmi_header) {
[][532] +                        .type = data[0],
[][533] +                        .length = data[1],
[][534] +                        .handle = WORD(data + 2),
[][535] +                        .data = data,
